import{_ as r,o,c as a,ag as n}from"./chunks/framework.Bgwu_dgr.js";const u=JSON.parse('{"title":"스킬 생태계","description":"","frontmatter":{},"headers":[],"relativePath":"topics/ecosystem.md","filePath":"topics/ecosystem.md","lastUpdated":null}'),e={name:"topics/ecosystem.md"};function s(i,t,l,g,p,h){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="스킬-생태계" tabindex="-1">스킬 생태계 <a class="header-anchor" href="#스킬-생태계" aria-label="Permalink to &quot;스킬 생태계&quot;">​</a></h1><p>발표 중반부에서 Zhang과 Murag은 구체적인 숫자를 제시한다. Anthropic이 Agent Skills를 공식 출시한 지 <strong>5주</strong>, 그 사이에 <strong>수천 개의 스킬</strong>이 만들어졌다는 것이다. 이 생태계는 세 갈래로 분화하고 있다.</p><h2 id="세-갈래의-지형" tabindex="-1">세 갈래의 지형 <a class="header-anchor" href="#세-갈래의-지형" aria-label="Permalink to &quot;세 갈래의 지형&quot;">​</a></h2><h3 id="_1-기초-스킬-foundational" tabindex="-1">1. 기초 스킬(Foundational) <a class="header-anchor" href="#_1-기초-스킬-foundational" aria-label="Permalink to &quot;1. 기초 스킬(Foundational)&quot;">​</a></h3><p>범용적이거나 도메인 전반에 쓰이는 스킬들. Anthropic 자체가 발행하거나, 과학/학술 도메인의 파트너들이 만든 것들이 여기에 속한다.</p><ul><li><strong>Anthropic의 문서 스킬</strong> -- Word, Excel, PowerPoint, PDF 등 오피스 문서 작성/편집의 표준 절차를 패키지화.</li><li><strong>Cadence의 과학 연구 스킬</strong> -- 전자 건강 기록(EHR) 데이터 분석, 바이오인포매틱스 파이프라인 등 생명과학 연구에 필요한 절차들.</li></ul><p>이 층의 스킬은 &quot;누구나 쓸 만한&quot; 공통 인프라에 가깝다. 운영체제에 비유하면 <strong>시스템 라이브러리</strong>에 해당한다.</p><h3 id="_2-서드파티-스킬-third-party" tabindex="-1">2. 서드파티 스킬(Third-party) <a class="header-anchor" href="#_2-서드파티-스킬-third-party" aria-label="Permalink to &quot;2. 서드파티 스킬(Third-party)&quot;">​</a></h3><p>특정 SaaS나 플랫폼과 연동된 스킬들. 자사 제품을 에이전트 생태계에 접목하려는 업체들이 만든다.</p><ul><li><strong>Browserbase의 Stagehand 스킬</strong> -- 에이전트가 브라우저를 자동화된 방식으로 다루는 절차. 웹 페이지를 열고, 폼을 채우고, 데이터를 추출하는 작업을 표준화.</li><li><strong>Notion 스킬</strong> -- 워크스페이스 안의 문서를 이해하고, 연구를 수행하며, 보고서를 작성하는 절차.</li></ul><p>서드파티 스킬은 &quot;각 SaaS 업체가 만드는 <strong>자사 제품의 사용 설명서</strong>이자 <strong>자동화 규약</strong>&quot;이다. MCP 서버와 함께 제공되면서 연결(MCP) + 절차(스킬)의 쌍을 이루는 경우가 많다.</p><h3 id="_3-엔터프라이즈-스킬-enterprise" tabindex="-1">3. 엔터프라이즈 스킬(Enterprise) <a class="header-anchor" href="#_3-엔터프라이즈-스킬-enterprise" aria-label="Permalink to &quot;3. 엔터프라이즈 스킬(Enterprise)&quot;">​</a></h3><p>개별 조직의 내부 지식을 담은 스킬. 공개 생태계에는 노출되지 않지만, 조직 안에서 가장 큰 가치를 만들어내는 층이다.</p><ul><li><strong>개발자 생산성 팀</strong> -- 사내 코드 스타일, 내부 프레임워크 사용법, 빌드/배포 규약을 스킬로 인코딩해 수천 명의 엔지니어에게 제공.</li><li><strong>법무/재무/회계</strong> -- 계약서 리뷰 체크리스트, 분기 재무 마감 절차, 규정 준수 플로우를 스킬로 작성.</li><li><strong>Fortune 100 기업들의 조직 플레이북</strong> -- 발표자들이 &quot;기업 전용의 특이한 내부 소프트웨어 사용법&quot;까지 스킬로 물질화된다고 표현한 바로 그 영역.</li></ul><p>Zhang과 Murag이 특히 강조하는 것은, 이 <strong>엔터프라이즈 스킬을 만드는 사람들 중 상당수가 개발자가 아니라는 사실</strong>이다.</p><h2 id="비개발자의-등장" tabindex="-1">비개발자의 등장 <a class="header-anchor" href="#비개발자의-등장" aria-label="Permalink to &quot;비개발자의 등장&quot;">​</a></h2><p>스킬은 원래 개발자를 위한 도구처럼 보였다. 그러나 실제 생태계에서는 법무 담당자, 리크루터, 회계사, 재무 분석가들이 스킬을 만들고 있다. 이들이 만드는 스킬의 특징은 이렇다.</p><ul><li><strong>코드가 거의 없다.</strong> 대부분 마크다운 문서로 구성된다.</li><li><strong>절차가 매우 구체적이다.</strong> 실무자가 수백 번 반복한 플로우가 그대로 기록된다.</li><li><strong>도메인 특유의 예외 케이스</strong>가 풍부하다. 표준 프롬프트로는 다루기 어려운 변종들.</li></ul><p>이 관찰이 의미하는 바는 크다. <strong>에이전트를 확장하는 일이 더 이상 엔지니어의 전유물이 아니다.</strong> 누구든 자신의 전문성을 폴더 안에 정리해 넣으면, 조직의 모든 에이전트가 그것을 공유한다.</p><blockquote><p>스킬은 코딩을 하지 않는 사람들이 범용 에이전트를 확장하는 수단이 되었다.</p></blockquote><h2 id="복잡도의-진화" tabindex="-1">복잡도의 진화 <a class="header-anchor" href="#복잡도의-진화" aria-label="Permalink to &quot;복잡도의 진화&quot;">​</a></h2><p>생태계에는 또 다른 흥미로운 흐름이 있다. 스킬은 처음에는 단순한 마크다운 한 장이지만, 시간이 지나면서 복잡해진다.</p><ul><li><strong>분 단위</strong>로 만들어지는 최소 스킬 -- 한두 번의 작업을 자동화하려는 시도.</li><li><strong>시간 단위</strong>로 만들어지는 중간 규모 스킬 -- 팀 내부에서 재사용되며 다듬어지는 절차.</li><li><strong>주/월 단위</strong>로 관리되는 대형 스킬 -- 여러 스크립트, 참조 문서, 바이너리까지 포함한 본격적인 도메인 패키지.</li></ul><p>큰 스킬은 점차 <strong>소프트웨어 제품의 성격</strong>을 띤다. 테스트가 붙고, 버전이 관리되고, 의존성이 문서화된다. 발표자들은 이 흐름에 맞춰 스킬을 소프트웨어처럼 다루기 위한 툴링이 필요하다고 본다 -- 테스트 프레임워크, 출력 품질 측정, 스킬 간 의존성 선언 등.</p><h2 id="mcp와-함께-수직-시장을-빠르게-여는-조합" tabindex="-1">MCP와 함께 -- 수직 시장을 빠르게 여는 조합 <a class="header-anchor" href="#mcp와-함께-수직-시장을-빠르게-여는-조합" aria-label="Permalink to &quot;MCP와 함께 -- 수직 시장을 빠르게 여는 조합&quot;">​</a></h2><p>스킬 생태계는 MCP 생태계와 맞물려 성장한다. Anthropic은 이 조합을 활용해 수직 시장을 빠르게 개척했다.</p><ul><li><strong>금융 서비스(Financial Services)</strong> -- 금융 데이터 API(MCP)와 재무 분석 절차(스킬)의 조합.</li><li><strong>생명과학(Life Sciences)</strong> -- 과학 데이터베이스 연결(MCP)과 연구 플레이북(스킬)의 조합.</li></ul><p>이 패턴은 스타트업과 엔터프라이즈 모두에게 같은 교훈을 준다. <strong>새로운 도메인에 진입할 때, 에이전트를 처음부터 만들지 말고 MCP + 스킬 조합을 맞추라.</strong> 범용 에이전트를 그대로 활용하면서, 도메인 지식만 스킬로 주입하면 된다. 수개월 걸리던 일이 수주 안에 끝난다.</p><h2 id="생태계가-암시하는-미래" tabindex="-1">생태계가 암시하는 미래 <a class="header-anchor" href="#생태계가-암시하는-미래" aria-label="Permalink to &quot;생태계가 암시하는 미래&quot;">​</a></h2><p>5주 만에 수천 개. 이 숫자가 가진 의미는 단순한 &quot;초반의 열기&quot;가 아니다. <strong>스킬이 만드는 게 이렇게 빠른 이유</strong>는, 이 물건이 <strong>기존의 협업 도구(Git, Drive, ZIP)</strong> 위에서 작동하기 때문이다. 새로운 플랫폼에 가입할 필요도, 새 SDK를 배울 필요도 없다.</p><p>생태계가 성장하는 속도는 이 **마찰 없음(frictionlessness)**에서 나온다. 그리고 이 지점이, 스킬이 단순한 기능 확장이 아니라 <strong>새로운 소프트웨어 층의 시작</strong>일 수 있다는 주장을 가능하게 한다.</p>',31)])])}const d=r(e,[["render",s]]);export{u as __pageData,d as default};
